<script type="text/javascript">
    jQuery(document).ready(function($) {
        $('.add_new_address_btn').on('click', function() {
            $('#address_id').val('');
            $('#full_name').val('');
            $('#phone_number').val('');
            $('#full_address').val('');
            $('.address_type:checked').val('');
            $('#is_default').prop('checked', false);
            $("#address-book .address-list").hide();
            $("#address-book .address-add-new").show();
        });

        $('.page-wrapper.my-account .add_new_address_btn').on('click', function() {
            $(".address-add-new").show();
            $("html").toggleClass("overflow-scroll");
            $("#popup_overlay").toggle();
        });

        // Hiển thị popup sửa địa chỉ
        $('.edit-address').on('click', function() {
            $(".address-add-new").show();
            $("html").toggleClass("overflow-scroll");
            $("#popup_overlay").toggle();
            $("h3 .type-add, .button .type-add").hide();
            $("h3 .type-edit, .button .type-edit").show();

            var id = $(this).data('id'),
                name = $(this).data('name'),
                phone = $(this).data('phone'),
                address = $(this).data('address'),
                type = $(this).data('type'),
                is_default = $(this).data('default') == 1;

            $(".type-checkbox .checkbox-item").find("input").each(function(index) {
                if ($(this).val() == type) $(this).prop('checked', true);
            });

            $('#address_id').val(id);
            $('#full_name').val(name);
            $('#phone_number').val(phone);
            $('#full_address').val(address);
            $('.address_type:checked').val(type);
            $('#is_default').prop('checked', is_default);

        });

        $('#address_book_section .inner-top span.mfp-close').on('click', function() {
            $("#address_book_section .popup-current").hide();
            $("html").removeClass("overflow-scroll");
            $("#popup_overlay").hide();
        });

        $('#address_book_section .inner-bottom .back').on('click', function() {
            $("#address_book_section .popup-current").hide();
            $("html").removeClass("overflow-scroll");
            $("#popup_overlay").hide();
        });

        $('#save_address').on('click', function() {
            var newAddressData = {
                action: 'save_new_address',
                id: $('#address_id').val(),
                name: $('#full_name').val().trim(),
                phone: $('#phone_number').val().trim(),
                address: $('#full_address').val().trim(),
                address_type: $('.address_type:checked').val(),
                is_default: $('#is_default').is(':checked') ? 1 : 0
            };
            if (!newAddressData.name || !newAddressData.phone || !newAddressData.address) {
                alert('Vui lòng điền đầy đủ thông tin.');
                return;
            }
            var phonePattern = /^[0-9]{10,15}$/;
            if (!phonePattern.test(newAddressData.phone)) {
                alert('Số điện thoại không hợp lệ. Vui lòng nhập số từ 10 đến 15 chữ số.');
                return;
            }
            $.post(woocommerce_params.ajax_url, newAddressData, function(response) {
                if (response.success) {
                    alert(response.data);
                    location.reload();
                } else {
                    alert(response.data);
                }
            });
        });

        $('.delete-address').on('click', function() {
            var addressId = $(this).data('id');
            var confirmDelete = confirm('Bạn có chắc chắn muốn xóa địa chỉ này không?');
            if (confirmDelete) {
                $.post(woocommerce_params.ajax_url, {
                    action: 'delete_address',
                    id: addressId
                }, function(response) {
                    if (response.success) {
                        alert(response.data);
                        location.reload();
                    } else {
                        alert(response.data);
                    }
                });
            }
        });
    });
</script>				</div>
