                $('#additional_fields').hide();
                $('.someone-receive').removeClass('active');
            }
        });
        $('#invoice_checkbox').on('change', function() {
            if ($(this).is(':checked')) {
                $('#invoice_fields input').attr('required', 'required');
                $('#invoice_fields input').attr('disabled', false);
                $('#invoice_fields').addClass('active');
            } else {
                $('#invoice_fields input').removeAttr('required');
                $('#invoice_fields').removeClass('active');
                $('#invoice_fields input').attr('disabled', true);
            }
        });
    });
