</div><script>function configuration() {
    var checkoutDescription1 = document.querySelector("#script-checkout-container");
    var fundiinTitle = fundiin.title;
    var fundiinDescription1;
    var maxPromotionText=3;
    
    var defaultThumbNail="https://assets.fundiin.vn/merchant/promo_100k.png";
    var fundiinThumbNail= typeof fundiin.promotions[0] != 'undefined' && typeof fundiin.promotions[0].thumbnail != 'undefined' ? fundiin.promotions[0].thumbnail : defaultThumbNail;
    var fundiinLogoImage = "https://assets.fundiin.vn/merchant/logo_transparent.png";
    
    if ( typeof fundiin.promotions != 'undefined' && fundiin.promotions.length > 0  && fundiin.promotions[0].checkout_description != null) {
    	    var template= '<p><strong>Mua trước Trả sau linh hoạt đến 12 tháng - chuẩn 3 KHÔNG với Fundiin</strong></p>';
            vvar groupsText = '<li>Không lãi suất - không phí ẩn</li><li>Không thủ tục rườm rà - chỉ với CCCD và hình selfie</li><li> Không chờ đợi - xét duyệt nhanh chóng</li>';
            var groupTemplate = '<ul>'+ groupsText + '</ul>';
            var promotionText = '';
            for (var i = 0; i < maxPromotionText; i++) {
                if(fundiin.promotions[i].checkout_description){
                    promotionText += '<li>'+ fundiin.promotions[i].checkout_description +'</li>';
                }
            }
            
            var promotionTemplate= '<ul>' + promotionText + '</ul>';
           fundiinDescription1 = template + groupTemplate + '<strong>Ưu đãi*:</strong>' + promotionTemplate + '(*) Mã được nhập tại giao diện thanh toán của Fundiin';
        }
    else{
    	    
    	    fundiinDescription1 = fundiin.description;
    	}
    
    var title = '<span id="fundiin-logo-2265" style="display:flex;justify-content:space-between;">'
              +     '<span>' + fundiinTitle + '</span>'
              +     '<span id="fundiin-trigger"></span>'
              +     '<div id="imageFundiin">'
              +       '<span>'
              +         '<img id="fundiin-image-2251" style="margin-left:10px;height:18px;"src="' + fundiinLogoImage + '">'
              +       '</span>'
              +       '<span>'
              +         '<img src="' + defaultThumbNail + '" style="height:20px;margin-left:5%;" />'
              +       '</span>'
              +     '</div>'
              + '</span>';
              
              
  if (typeof checkoutDescription1 !== 'undefined' && checkoutDescription1 !== null) {
    checkoutDescription1.innerHTML = fundiinDescription1;
  }
  
  
  
  var fundiinLable = getElementByXpath("//*[contains(text(), 'Thanh toán trả sau cùng Fundiin')]");
  if (fundiinLable != null ) {
    fundiinLable.innerHTML= title;
  }
  else {
    var paymentLabel = document.querySelector('label[for="payment_method_fundiin"]');
    if (typeof paymentLabel !== 'undefined' && paymentLabel !== null) {
        paymentLabel.innerHTML = title;
    }
  }
  
  var paymentWooLabel = document.querySelector('div.payment_box.payment_method_fundiin');
  if( typeof paymentWooLabel !== 'undefined' && paymentWooLabel !== null){
    paymentWooLabel.innerHTML= fundiinDescription1;
  }
}
function getElementByXpath(path) {
  return document.evaluate(path, document, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null).singleNodeValue;
}

function configurationStyle() {
    var style = "<style>";
    style += "</style>";
    document.head.insertAdjacentHTML('beforeend', style );
}
function removeGateway() {
    
    var fundiinGW = $("div#script-checkout-container").closest("div.radio-wrapper");
    var allGW = fundiinGW.parent();
    var tableRows = document.querySelectorAll("tr.product");
    for( var tableRow of tableRows ) {
        var productName = tableRow.querySelector("span.product__description__name").innerHTML.trim();
        if (fundiin.block_all_products == "true") {
            if ( !fundiin.banned_products.includes(productName) ) {
                fundiinGW.remove();
                allGW.children().eq(0).find("input").prop("checked", true);
                return;
            }
        }
        else {
            if ( fundiin.banned_products.includes(productName) ) {
                fundiinGW.remove();
                allGW.children().eq(0).find("input").prop("checked", true);
                return;
            }  
        }
        
    }
        
    var totalBill = parseFloat( document.querySelector(".order-summary-toggle__total-recap").innerHTML.replace(/[ntâ‚«,.]/g, "") );
    if ( fundiin.visible == false || totalBill > fundiin.max_fundiin_order_price || totalBill < fundiin.min_fundiin_order_price ) {
        fundiinGW.remove();
        allGW.children().eq(0).find("input").prop("checked", true);
    }
}
function moveGatewayToTop() {
    if (fundiin.visible == false ) return;
    var fundiinElement = document.querySelector("#script-checkout-container");
    if (fundiinElement) {
        var boxGateway = fundiinElement.closest("div.radio-wrapper");
    	var parent = boxGateway.parentNode;
    	var firstChild = parent.children[0];
    	if ( firstChild != boxGateway ) {
        	parent.insertBefore(boxGateway, firstChild);
     	}
    }
}

function setupWidgets() {
    
    if ( fundiin.widgets.length ) {
        for ( var widget of fundiin.widgets ) {
            if (widget && widget.trigger_selector) {
                var triggerElements = document.querySelectorAll(widget.trigger_selector);
                if ( triggerElements != null ) {
                    for ( var triggerElement of Array.from(triggerElements)) {
                        triggerElement.insertAdjacentHTML( widget.trigger_orientation, widget.trigger_html);
                    }
                }
            }
            
            if (widget && widget.widget_selector) {
                var widgetElements = document.querySelectorAll(widget.widget_selector);
                if ( widgetElements != null && !!widget.widget_html ) {
                    for ( var widgetElement of Array.from(widgetElements)) {
                        widgetElement.insertAdjacentHTML( widget.widget_orientation, widget.widget_html );
                    }
                    
                }
            }
            

            if ( widget && widget.widget_css ) {
                document.head.insertAdjacentHTML('beforeend', '<style>' + widget.widget_css + '</style>' );
            }
        
            if (widget && widget.libraries.length ) {

                for ( var lib of widget.libraries ) {
                    var element = document.createElement( lib.lib_type );
                    if ( lib.lib_type == "script" ) {
                        
                        element.src = lib.lib_source;
                        element[lib.lib_mode] = true;
                        document.body.appendChild( element );
                    }
                    else { /* style */
                        element.rel = "stylesheet";
                        element.href = lib.lib_source;
                        document.head.appendChild( element );
                    }
                }
            }
            
            if (widget && widget.widget_js) {
                /* add script for widget*/
                var widgetJs = document.createElement("script");
                widgetJs.innerHTML = widget.widget_js;
                document.body.appendChild( widgetJs );
            }
        }
    }
}
configuration();</script>
