	function sendChatwootMessage(content, label, cwConversationValue) {
		const CONFIG = {
			BASE_URL: "https://erp.nvbplay.vn",
			WEBSITE_TOKEN: "AmMAheUb69x3QB7gHf1mFaki"
		};
		window.$chatwoot.toggle("open");
		window.$chatwoot.setLabel(label);
		jQuery.ajax({
			url: `${CONFIG.BASE_URL}/api/v1/widget/messages`,
			type: "POST",
			data: JSON.stringify({
				message: {
					content,
					reply_to: null,
					referer_url: "https://nvbplay.vn/checkout"
				}
			}),
			headers: {
				"x-auth-token": cwConversationValue,
				"Content-Type": "application/json"
			},
			dataType: "json",
			data: {
				website_token: CONFIG.WEBSITE_TOKEN,
				cw_conversation: cwConversationValue,
				locale: "vi"
			}
		}).then(
			res => console.log(res),
			err => console.error("Error:", err)
		);
	}
	window.addEventListener('chatwoot:ready', () => {
		var iframe = document.getElementById("chatwoot_live_chat_widget"),
